export const TEXTURE_ORDER = [
  'microcement',
  'brushedSteel',
  'matteCeramic',
  'obsidianClearcoat',
  'alcantaraSuede',
  'kelvinGradient'
]

export function resolveTextureKey(key) {
  if (TEXTURE_PRESETS[key]) return key
  return LEGACY_TEXTURE_MAP[key] || 'microcement'
}

export function applyStateTint(baseHex, lightHex, amount) {
  const base = new THREE.Color(baseHex)
  const light = new THREE.Color(lightHex)
  base.lerp(light, amount)
  return base
}
