import { VOICE_STATES } from './voiceStates'

export const ZERO_TUNE_STORAGE_KEY = 'leela_zero_state_defaults_v1'
export const ZERO_SCENE_STORAGE_KEY = 'leela_zero_scene_config_v1'
export const ZERO_DEFAULTS_UPDATED_EVENT = 'leela-zero-defaults-updated'
export const ZERO_API_BASE_STORAGE_KEY = 'leela_zero_api_base_v1'

export const ZERO_TUNE_STATE_ORDER = [
  'idle',
  'listening',
  'thinking',
  'speaking',
  'interrupted'
]

export const DEFAULT_BACKGROUND_CANVAS_PCT = 6

const TEXTURE_KEYS = new Set([
  'microcement',
  'brushedSteel',
  'matteCeramic',
  'obsidianClearcoat',
  'alcantaraSuede',
  'kelvinGradient',
  'polishedAluminium',
  'mirrorChrome'
])

export function canvasPctToHex(pct) {
  const v = Math.round((Math.min(100, Math.max(0, Number(pct) || 0)) * 255) / 100)
  const h = v.toString(16).padStart(2, '0')
  return `#${h}${h}${h}`
}

export function createBaselineOverride(zeroKey) {
  const base = VOICE_STATES[zeroKey] || VOICE_STATES.idle
  return {
    poolSpreadPct: 52,
    poolIntensityPct: 62,
    poolLightColor: base.light,
    textureKey: 'microcement',
    keyAzimuth: 0,
    keyKelvin: 4500,
    keyIntensityPct: 28
  }
}

export function normalizeStateOverride(zeroKey, raw) {
  const baseline = createBaselineOverride(zeroKey)
  if (!raw || typeof raw !== 'object') return baseline
  return {
    poolSpreadPct: clampPct(raw.poolSpreadPct, baseline.poolSpreadPct),
    poolIntensityPct: clampPct(raw.poolIntensityPct, baseline.poolIntensityPct),
    poolLightColor: normalizeHex(raw.poolLightColor, baseline.poolLightColor),
    textureKey: TEXTURE_KEYS.has(raw.textureKey) ? raw.textureKey : baseline.textureKey,
    keyAzimuth: clampNum(raw.keyAzimuth, -90, 90, baseline.keyAzimuth),
    keyKelvin: clampNum(raw.keyKelvin, 2700, 6500, baseline.keyKelvin),
    keyIntensityPct: clampPct(raw.keyIntensityPct, baseline.keyIntensityPct)
  }
}

function clampPct(value, fallback) {
  const n = Number(value)
  if (!Number.isFinite(n)) return fallback
  return Math.round(Math.min(100, Math.max(0, n)))
}

function clampNum(value, min, max, fallback) {
  const n = Number(value)
  if (!Number.isFinite(n)) return fallback
  return Math.min(max, Math.max(min, n))
}

function normalizeHex(value, fallback) {
  const hex = String(value || '').trim()
  if (/^#[0-9a-fA-F]{6}$/.test(hex)) return hex.toLowerCase()
  return fallback
}

export function createDefaultSceneConfig() {
  return { backgroundCanvasPct: DEFAULT_BACKGROUND_CANVAS_PCT }
}

export function normalizeSceneConfig(raw) {
  const baseline = createDefaultSceneConfig()
  if (!raw || typeof raw !== 'object') return baseline
  return {
    backgroundCanvasPct: clampPct(raw.backgroundCanvasPct, baseline.backgroundCanvasPct)
  }
}

export function loadLocalDefaults() {
  try {
    const raw = window.localStorage.getItem(ZERO_TUNE_STORAGE_KEY)
    if (!raw) return {}
    const parsed = JSON.parse(raw)
    if (!parsed || typeof parsed !== 'object') return {}
    const out = {}
    for (const key of ZERO_TUNE_STATE_ORDER) {
      if (parsed[key]) out[key] = normalizeStateOverride(key, parsed[key])
    }
    return out
  } catch {
    return {}
  }
}

export function loadLocalSceneConfig() {
  try {
    const raw = window.localStorage.getItem(ZERO_SCENE_STORAGE_KEY)
    if (!raw) return createDefaultSceneConfig()
    return normalizeSceneConfig(JSON.parse(raw))
  } catch {
    return createDefaultSceneConfig()
  }
}

export function saveLocalDefaults(all) {
  const payload = {}
  for (const key of ZERO_TUNE_STATE_ORDER) {
    if (all[key]) payload[key] = normalizeStateOverride(key, all[key])
  }
  window.localStorage.setItem(ZERO_TUNE_STORAGE_KEY, JSON.stringify(payload))
  window.dispatchEvent(new CustomEvent(ZERO_DEFAULTS_UPDATED_EVENT))
}

export function saveLocalSceneConfig(scene) {
  const payload = normalizeSceneConfig(scene)
  window.localStorage.setItem(ZERO_SCENE_STORAGE_KEY, JSON.stringify(payload))
  window.dispatchEvent(new CustomEvent(ZERO_DEFAULTS_UPDATED_EVENT))
}

export function getApiBase() {
  try {
    const params = new URLSearchParams(window.location.search)
    const fromQuery = params.get('api')
    if (fromQuery) return fromQuery.replace(/\/$/, '')
    const stored = window.localStorage.getItem(ZERO_API_BASE_STORAGE_KEY)
    if (stored) return stored.replace(/\/$/, '')
  } catch {
    /* ignore */
  }
  return 'http://127.0.0.1:4173'
}

export function setApiBase(url) {
  const trimmed = String(url || '').trim().replace(/\/$/, '')
  if (trimmed) {
    window.localStorage.setItem(ZERO_API_BASE_STORAGE_KEY, trimmed)
  } else {
    window.localStorage.removeItem(ZERO_API_BASE_STORAGE_KEY)
  }
}

async function fetchJson(path, options) {
  const base = getApiBase()
  const url = `${base}${path}`
  const response = await fetch(url, options)
  if (!response.ok) throw new Error(await response.text())
  return response.json()
}

export async function fetchServerDefaults() {
  const data = await fetchJson('/api/zero-mascot-defaults')
  const out = {}
  for (const key of ZERO_TUNE_STATE_ORDER) {
    if (data.defaults?.[key]) out[key] = normalizeStateOverride(key, data.defaults[key])
  }
  if (data.scene) saveLocalSceneConfig(data.scene)
  return out
}

export async function persistServerDefaults(all, scene = null) {
  const defaults = {}
  for (const key of ZERO_TUNE_STATE_ORDER) {
    defaults[key] = normalizeStateOverride(key, all[key])
  }
  const payload = { defaults }
  if (scene) payload.scene = normalizeSceneConfig(scene)
  return fetchJson('/api/zero-mascot-defaults', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload)
  })
}

export function draftToUi(draft) {
  return {
    poolSpread: draft.poolSpreadPct,
    poolIntensity: draft.poolIntensityPct,
    poolColor: draft.poolLightColor,
    textureKey: draft.textureKey,
    keyAzimuth: draft.keyAzimuth,
    keyKelvin: draft.keyKelvin,
    keyIntensity: draft.keyIntensityPct
  }
}

export function uiToDraft(ui) {
  return {
    poolSpreadPct: ui.poolSpread,
    poolIntensityPct: ui.poolIntensity,
    poolLightColor: ui.poolColor,
    textureKey: ui.textureKey,
    keyAzimuth: ui.keyAzimuth,
    keyKelvin: ui.keyKelvin,
    keyIntensityPct: ui.keyIntensity
  }
}

export function buildInitialDrafts() {
  const local = loadLocalDefaults()
  const drafts = {}
  for (const key of ZERO_TUNE_STATE_ORDER) {
    drafts[key] = local[key] || createBaselineOverride(key)
  }
  return drafts
}
